//! # Actr - Actor-RTC Framework
//!
//! Actr is a distributed Actor framework based on WebRTC for building real-time communication systems.
//!
//! ## Quick Start
//!
//! ```rust,ignore
//! use actr::prelude::*;
//!
//! #[derive(Default)]
//! struct MyActor;
//!
//! // MessageDispatcher is generated by actr-cli codegen
//! #[async_trait]
//! impl Workload for MyActor {
//!     type Dispatcher = MyActorDispatcher;
//!
//!     async fn on_start<C: Context>(&self, ctx: &C) -> ActorResult<()> {
//!         // Use logging as needed
//!         Ok(())
//!     }
//! }
//! ```

#![warn(missing_docs)]

// ============================================================================
// Protocol - Core protocol types
// ============================================================================

/// Protocol module - core protocol definitions
pub use actr_protocol as protocol;

// Re-export commonly used protocol types
pub use actr_protocol::{
    ActorResult, ActrError, ActrId, ActrType, PayloadType, RpcEnvelope, RpcRequest,
};

// ============================================================================
// Framework - Core framework abstractions
// ============================================================================

/// Framework module - core framework abstractions
pub use actr_framework as framework;

// Re-export core framework types
pub use actr_framework::{Context, MessageDispatcher, Workload};

// ============================================================================
// Hyper - Runtime infrastructure (optional)
// ============================================================================

#[cfg(feature = "runtime")]
/// Hyper module - runtime infrastructure (ActrSystem, transport, wire, lifecycle)
pub use actr_hyper as hyper;

// ============================================================================
// Runtime - Business dispatch layer (optional)
// ============================================================================

#[cfg(feature = "runtime")]
/// Runtime module - business dispatch (ACL + dispatch)
pub use actr_runtime as runtime;

// ============================================================================
// Config - Configuration support (optional)
// ============================================================================

#[cfg(feature = "config")]
/// Config module - configuration file parsing
pub use actr_config as config;

// ============================================================================
// Prelude - Common imports
// ============================================================================

/// Prelude module - contains the most commonly used types and traits
///
/// Recommended usage: `use actr::prelude::*;` in application code to import all necessary types.
pub mod prelude {
    // Protocol layer - core types
    pub use crate::protocol::{
        ActorResult, ActrError, ActrId, ActrType, PayloadType, RpcEnvelope, RpcRequest,
    };

    // Framework layer - core traits and types
    pub use crate::framework::{Context, MessageDispatcher, Workload};

    // Runtime infrastructure - ActrSystem / ActrNode / ActrRef
    #[cfg(feature = "runtime")]
    pub use crate::hyper::{ActrNode, ActrRef, ActrSystem};

    // Common traits and types
    pub use async_trait::async_trait;
    pub use std::sync::Arc;
}
